import React from 'react';
import { useAuth } from '../../contexts/AuthContext';

const CustomerProfile = () => {
  const { user } = useAuth();

  return (
    <div>
      <h1 style={{ fontSize: '24px', fontWeight: '600', marginBottom: '24px' }}>My Profile</h1>
      <div className="card">
        <div style={{ textAlign: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '64px', marginBottom: '8px' }}>👤</div>
          <h2 style={{ fontSize: '20px', fontWeight: '600' }}>{user?.first_name} {user?.last_name}</h2>
          <p style={{ color: '#6b7280' }}>{user?.email}</p>
        </div>
        
        <div style={{ borderTop: '1px solid #e5e7eb', paddingTop: '20px' }}>
          <div style={{ marginBottom: '16px' }}>
            <label style={{ fontSize: '14px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Phone</label>
            <p>{user?.phone || 'Not provided'}</p>
          </div>
          <div>
            <label style={{ fontSize: '14px', color: '#6b7280', display: 'block', marginBottom: '4px' }}>Address</label>
            <p>{user?.address || 'Not provided'}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CustomerProfile;
